import requests

def search_azure_samples(topic: str, language: str = "") -> list[dict]:
    """
    Search the Azure Samples GitHub organisation for repositories matching a topic.
    Uses the GitHub Search API — no authentication required for public repos.
    """
    query = f"org:Azure-Samples {topic}"
    if language:
        query += f" language:{language}"

    url = "https://api.github.com/search/repositories"
    params = {"q": query, "sort": "updated", "order": "desc", "per_page": 10}
    headers = {"Accept": "application/vnd.github.v3+json"}

    resp = requests.get(url, params=params, headers=headers, timeout=15)
    resp.raise_for_status()

    return [
        {
            "name": r["name"],
            "description": r.get("description", ""),
            "url": r["html_url"],
            "stars": r["stargazers_count"],
            "updated": r["updated_at"][:10],
            "language": r.get("language"),
        }
        for r in resp.json().get("items", [])
    ]

# Find Python FastAPI samples updated recently
samples = search_azure_samples("fastapi", language="Python")
for s in samples[:5]:
    print(f"[{s['stars']}★] {s['name']} — {s['description'][:60]}")
    print(f"     {s['url']} (updated {s['updated']})")
